    94→				{Name: "editor2", Command: "cmd2 {path}", Available: false},
    95→			},
    96→			want: "editor1",
    97→		},
    98→		{
    99→			name:    "no editors",
   100→			editors: []config.EditorConfig{},
   101→			want:    "",
   102→		},
   103→	}
   104→
   105→	for _, tt := range tests {
   106→		t.Run(tt.name, func(t *testing.T) {
   107→			executor := &Executor{
