     3→import (
     4→	"encoding/json"
     5→	"net"
     6→	"os"
     7→	"os/exec"
     8→	"strings"
     9→)
    10→
    11→// TailscaleStatus represents the minimal Tailscale status we need
    12→type TailscaleStatus struct {
    13→	Self struct {
    14→		HostName string `json:"HostName"`
    15→		DNSName  string `json:"DNSName"`
    16→		TailAddr string `json:"TailscaleIPs,omitempty"`
    17→	} `json:"Self"`
    18→}
    19→
    20→// DetectTailscaleHost attempts to detect if we're connected via Tailscale
    21→// and returns an appropriate hostname to use
    22→func DetectTailscaleHost(sshClientIP string, pattern string) (string, bool) {
    23→	// First check if Tailscale is running and we have a Tailscale IP
    24→	tailscaleIP := GetTailscaleInterface()
    25→	if tailscaleIP == "" {
    26→		return "", false
    27→	}
    28→
    29→	// Check multiple indicators for Tailscale connection:
    30→	// 1. SSH client IP is in Tailscale range
    31→	// 2. We have a Tailscale interface
    32→	// 3. SSH TTY exists (we're in SSH session)
    33→	isViaTS := isTailscaleIP(sshClientIP) || (tailscaleIP != "" && os.Getenv("SSH_TTY") != "")
    34→
    35→	if !isViaTS {
    36→		return "", false
    37→	}
    38→
    39→	// Try to get Tailscale hostname
    40→	hostname := getTailscaleHostname()
    41→	if hostname != "" {
    42→		// Try common suffixes used in Tailscale networks
    43→		// Most users append "tail" to their hostname for Tailscale
    44→		baseName := strings.TrimSuffix(hostname, ".tail75a81.ts.net.")
    45→		baseName = strings.TrimSuffix(baseName, ".ts.net.")
    46→
    47→		// Apply pattern if provided
    48→		var tailName string
    49→		if pattern != "" {
    50→			// Replace {hostname} placeholder with the base name
    51→			tailName = strings.ReplaceAll(pattern, "{hostname}", baseName)
    52→			// Also support {hostname-} which removes hyphens
    53→			tailName = strings.ReplaceAll(tailName, "{hostname-}", strings.ReplaceAll(baseName, "-", ""))
    54→		} else {
    55→			// Default pattern: ws-01 -> ws01tail
    56→			tailName = strings.ReplaceAll(baseName, "-", "") + "tail"
    57→		}
    58→
    59→		return tailName, true
    60→	}
    61→
    62→	return "", false
    63→}
    64→
    65→// isTailscaleIP checks if an IP is in the Tailscale range (100.64.0.0/10)
    66→func isTailscaleIP(ipStr string) bool {
    67→	if ipStr == "" {
    68→		return false
    69→	}
    70→
    71→	ip := net.ParseIP(ipStr)
    72→	if ip == nil {
    73→		return false
    74→	}
    75→
    76→	// Tailscale uses 100.64.0.0/10 (CGNAT range)
    77→	_, tailscaleNet, _ := net.ParseCIDR("100.64.0.0/10")
    78→	return tailscaleNet != nil && tailscaleNet.Contains(ip)
    79→}
    80→
    81→// getTailscaleHostname retrieves the hostname from Tailscale
    82→func getTailscaleHostname() string {
    83→	// Try to run tailscale status command
    84→	cmd := exec.Command("tailscale", "status", "--json")
    85→	output, err := cmd.Output()
    86→	if err != nil {
    87→		return ""
    88→	}
    89→
    90→	var status TailscaleStatus
    91→	if err := json.Unmarshal(output, &status); err != nil {
    92→		return ""
    93→	}
    94→
    95→	// Return the hostname from Tailscale
    96→	if status.Self.HostName != "" {
    97→		return status.Self.HostName
    98→	}
    99→
   100→	// Fallback to DNS name if hostname is not available
   101→	if status.Self.DNSName != "" {
   102→		return status.Self.DNSName
   103→	}
   104→
   105→	return ""
   106→}
   107→
   108→// GetTailscaleInterface returns the Tailscale interface IP if available
   109→func GetTailscaleInterface() string {
   110→	// Try to get tailscale0 interface IP
   111→	ifaces, err := net.Interfaces()
   112→	if err != nil {
   113→		return ""
   114→	}
   115→
   116→	for _, iface := range ifaces {
   117→		if iface.Name == "tailscale0" || iface.Name == "utun" {
   118→			addrs, err := iface.Addrs()
   119→			if err != nil {
   120→				continue
   121→			}
   122→			for _, addr := range addrs {
   123→				if ipnet, ok := addr.(*net.IPNet); ok && ipnet.IP.To4() != nil {
   124→					// Check if it's in Tailscale range
   125→					if isTailscaleIP(ipnet.IP.String()) {
   126→						return ipnet.IP.String()
   127→					}
   128→				}
   129→			}
   130→		}
   131→	}
   132→
   133→	return ""
   134→}
