     1→// Package main implements the rcode client CLI application.
     2→package main
     3→
     4→import (
     5→	"bytes"
     6→	"context"
     7→	"encoding/json"
     8→	"fmt"
     9→	"net/http"
    10→	"strings"
    11→	"time"
    12→
    13→	"github.com/foxytanuki/rcode/internal/config"
    14→	"github.com/foxytanuki/rcode/internal/logger"
    15→	"github.com/foxytanuki/rcode/internal/version"
    16→	"github.com/foxytanuki/rcode/pkg/api"
    17→)
    18→
    19→// Client represents the rcode CLI client
    20→type Client struct {
    21→	config     *config.ClientConfig
    22→	log        *logger.Logger
    23→	httpClient *http.Client
    24→}
    25→
    26→// NewClient creates a new client instance
    27→func NewClient(cfg *config.ClientConfig, log *logger.Logger) *Client {
    28→	// Create HTTP client with timeout
    29→	httpClient := &http.Client{
    30→		Timeout: cfg.Network.Timeout * 2, // Double the timeout for the full request
    31→	}
    32→
    33→	return &Client{
    34→		config:     cfg,
    35→		log:        log,
    36→		httpClient: httpClient,
    37→	}
    38→}
    39→
    40→// OpenEditor opens a file/directory in an editor on the host machine
    41→func (c *Client) OpenEditor(path, editor string, sshInfo *SSHInfo) error {
    42→	// Use default editor if not specified
    43→	if editor == "" {
    44→		editor = c.config.DefaultEditor
    45→	}
    46→
    47→	// Create the request
    48→	req := api.OpenRequest{
    49→		Path:   path,
    50→		Editor: editor,
    51→		User:   sshInfo.User,
    52→		Host:   sshInfo.Host,
    53→	}
    54→	req.SetTimestamp()
    55→
    56→	// Try primary host first
    57→	c.log.Debug("Attempting to connect to primary host",
    58→		"host", c.config.Hosts.Server.Primary,
    59→		"timeout", c.config.Network.Timeout,
    60→	)
    61→
    62→	err := c.sendRequest(c.config.Hosts.Server.Primary, req)
    63→	if err == nil {
    64→		return nil
    65→	}
    66→
    67→	c.log.Warn("Failed to connect to primary host",
    68→		"host", c.config.Hosts.Server.Primary,
    69→		"error", err,
    70→	)
    71→
    72→	// Try fallback host if configured
    73→	if c.config.Hosts.Server.Fallback != "" {
    74→		c.log.Debug("Attempting to connect to fallback host",
    75→			"host", c.config.Hosts.Server.Fallback,
    76→			"timeout", c.config.Network.Timeout,
    77→		)
    78→
    79→		err = c.sendRequest(c.config.Hosts.Server.Fallback, req)
    80→		if err == nil {
    81→			return nil
    82→		}
    83→
    84→		c.log.Warn("Failed to connect to fallback host",
    85→			"host", c.config.Hosts.Server.Fallback,
    86→			"error", err,
    87→		)
    88→	}
    89→
    90→	return fmt.Errorf("failed to connect to any configured host")
    91→}
    92→
    93→// sendRequest sends the open editor request to a specific host
    94→func (c *Client) sendRequest(host string, req api.OpenRequest) error {
    95→	// Ensure host includes port
    96→	if !strings.Contains(host, ":") {
    97→		host = fmt.Sprintf("%s:3339", host)
    98→	}
    99→
   100→	// Build URL
   101→	url := fmt.Sprintf("http://%s/open-editor", host)
   102→
   103→	// Marshal request to JSON
   104→	jsonData, err := json.Marshal(req)
   105→	if err != nil {
   106→		return fmt.Errorf("failed to marshal request: %w", err)
   107→	}
   108→
   109→	// Create context with timeout
   110→	ctx, cancel := context.WithTimeout(context.Background(), c.config.Network.Timeout)
   111→	defer cancel()
   112→
   113→	// Create HTTP request
   114→	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, url, bytes.NewReader(jsonData))
   115→	if err != nil {
   116→		return fmt.Errorf("failed to create request: %w", err)
   117→	}
   118→
   119→	httpReq.Header.Set("Content-Type", "application/json")
   120→	httpReq.Header.Set("User-Agent", fmt.Sprintf("rcode/%s", version.Version))
   121→
   122→	// Perform retries if configured
   123→	var lastErr error
   124→	attempts := c.config.Network.RetryAttempts
   125→	if attempts <= 0 {
   126→		attempts = 1
   127→	}
   128→
   129→	for i := 0; i < attempts; i++ {
   130→		if i > 0 {
   131→			c.log.Debug("Retrying request",
   132→				"attempt", i+1,
   133→				"max_attempts", attempts,
   134→			)
   135→			time.Sleep(c.config.Network.RetryDelay)
   136→		}
   137→
   138→		// Send request
   139→		resp, err := c.httpClient.Do(httpReq)
   140→		if err != nil {
   141→			lastErr = fmt.Errorf("request failed: %w", err)
   142→			continue
   143→		}
   144→
   145→		// Process response - close body when done
   146→		func() {
   147→			defer func() {
   148→				if err := resp.Body.Close(); err != nil {
   149→					c.log.Warn("Failed to close response body", "error", err)
   150→				}
   151→			}()
   152→
   153→			// Check status code
   154→			if resp.StatusCode == http.StatusOK {
   155→				// Parse successful response
   156→				var openResp api.OpenResponse
   157→				if err := json.NewDecoder(resp.Body).Decode(&openResp); err != nil {
   158→					lastErr = fmt.Errorf("failed to decode response: %w", err)
   159→					return
   160→				}
   161→
   162→				c.log.Info("Editor opened successfully",
   163→					"editor", openResp.Editor,
   164→					"command", openResp.Command,
   165→				)
   166→
   167→				lastErr = nil
   168→				return
   169→			}
   170→
   171→			// Parse error response
   172→			var errResp api.ErrorResponse
   173→			if err := json.NewDecoder(resp.Body).Decode(&errResp); err != nil {
   174→				lastErr = fmt.Errorf("server returned status %d", resp.StatusCode)
   175→			} else {
   176→				lastErr = fmt.Errorf("server error: %s", errResp.Error())
   177→			}
