   267→// GetManualCommand generates a manual command that can be run on the host
   268→// It first tries to fetch the command template from the server.
   269→// If the server is unreachable, it falls back to configured fallback editors.
   270→func (c *Client) GetManualCommand(path, editor string, sshInfo *SSHInfo) string {
   271→	// Use default editor if not specified
   272→	if editor == "" {
   273→		editor = c.config.DefaultEditor
   274→	}
   275→
   276→	// Try to fetch editor command from server
   277→	editorCmd := c.fetchEditorCommand(editor)
   278→
   279→	if editorCmd == "" {
   280→		// Fall back to configured fallback editors
   281→		if c.config.FallbackEditors != nil {
   282→			editorCmd = c.config.FallbackEditors[editor]
   283→		}
   284→	}
   285→
   286→	if editorCmd == "" {
   287→		return ""
   288→	}
   289→
   290→	// Replace placeholders
   291→	cmd := strings.ReplaceAll(editorCmd, "{user}", sshInfo.User)
   292→	cmd = strings.ReplaceAll(cmd, "{host}", sshInfo.Host)
   293→	cmd = strings.ReplaceAll(cmd, "{path}", path)
   294→
   295→	return cmd
   296→}
