    10→// SSHInfo contains information about the SSH connection
    11→type SSHInfo struct {
    12→	User       string
    13→	Host       string
    14→	ClientIP   string
    15→	ClientPort string
    16→	ServerIP   string
    17→	ServerPort string
    18→}
    19→
    20→// ExtractSSHInfo extracts SSH connection information from environment variables
    21→func ExtractSSHInfo() (SSHInfo, error) {
    22→	info := SSHInfo{}
    23→
    24→	// Check SSH_CONNECTION environment variable
    25→	// Format: client_ip client_port server_ip server_port
    26→	sshConnection := os.Getenv("SSH_CONNECTION")
    27→	if sshConnection != "" {
    28→		parts := strings.Fields(sshConnection)
    29→		if len(parts) >= 4 {
    30→			info.ClientIP = parts[0]
    31→			info.ClientPort = parts[1]
    32→			info.ServerIP = parts[2]
    33→			info.ServerPort = parts[3]
    34→		}
    35→	}
    36→
    37→	// Check SSH_CLIENT environment variable as fallback
    38→	// Format: client_ip client_port server_port
    39→	if info.ClientIP == "" {
    40→		sshClient := os.Getenv("SSH_CLIENT")
    41→		if sshClient != "" {
    42→			parts := strings.Fields(sshClient)
    43→			if len(parts) >= 3 {
    44→				info.ClientIP = parts[0]
    45→				info.ClientPort = parts[1]
    46→				// Note: SSH_CLIENT doesn't provide server IP, only server port
    47→				if info.ServerPort == "" {
    48→					info.ServerPort = parts[2]
    49→				}
    50→			}
    51→		}
    52→	}
    53→
    54→	// Extract username from USER or LOGNAME
    55→	info.User = os.Getenv("USER")
    56→	if info.User == "" {
    57→		info.User = os.Getenv("LOGNAME")
    58→	}
    59→
    60→	// Note: Host is NOT set here - it will be determined in main.go
    61→	// based on priority: config ssh_host > ClientIP > hostname > localhost
    62→
    63→	// Check if we're actually in an SSH session
    64→	if sshConnection == "" && os.Getenv("SSH_CLIENT") == "" && os.Getenv("SSH_TTY") == "" {
    65→		return SSHInfo{}, errors.New("not in an SSH session")
    66→	}
    67→
    68→	return info, nil
    69→}
    70→
    71→// IsSSHSession checks if the current process is running in an SSH session
    72→func IsSSHSession() bool {
    73→	// Check various SSH-related environment variables
    74→	return os.Getenv("SSH_CONNECTION") != "" ||
    75→		os.Getenv("SSH_CLIENT") != "" ||
    76→		os.Getenv("SSH_TTY") != ""
    77→}
    78→
    79→// GetSSHUser returns the SSH username, with fallbacks
    80→func GetSSHUser() string {
    81→	// Try SSH_USER first (some systems set this)
    82→	user := os.Getenv("SSH_USER")
    83→	if user != "" {
    84→		return user
    85→	}
    86→
    87→	// Try USER
    88→	user = os.Getenv("USER")
    89→	if user != "" {
    90→		return user
    91→	}
    92→
    93→	// Try LOGNAME
    94→	user = os.Getenv("LOGNAME")
    95→	if user != "" {
    96→		return user
    97→	}
    98→
    99→	// Last resort - try to get from whoami command
   100→	// This is not implemented here to avoid exec dependencies
   101→	return "unknown"
   102→}
   103→
   104→// GetSSHHost returns the SSH host information (defaults to client IP)
   105→func GetSSHHost() string {
   106→	// First check if we have client IP from SSH_CONNECTION
   107→	// This is the IP we want - where we SSHed FROM
   108→	sshConnection := os.Getenv("SSH_CONNECTION")
   109→	if sshConnection != "" {
   110→		parts := strings.Fields(sshConnection)
   111→		if len(parts) >= 4 {
   112→			// Return the client IP (where we're SSHing from)
   113→			return parts[0]
   114→		}
   115→	}
   116→
   117→	// Check SSH_CLIENT as fallback
   118→	sshClient := os.Getenv("SSH_CLIENT")
   119→	if sshClient != "" {
   120→		parts := strings.Fields(sshClient)
   121→		if len(parts) >= 1 {
   122→			return parts[0]
   123→		}
   124→	}
   125→
   126→	// Last resort - use hostname
   127→	hostname, err := os.Hostname()
   128→	if err == nil {
   129→		return hostname
   130→	}
   131→
   132→	return "localhost"
   133→}
   134→
   135→// ParseSSHDestination parses an SSH destination string (user@host)
   136→func ParseSSHDestination(destination string) (user, host string, err error) {
   137→	if destination == "" {
   138→		return "", "", errors.New("empty destination")
   139→	}
   140→
   141→	// Check for user@host format
   142→	if strings.Contains(destination, "@") {
   143→		parts := strings.SplitN(destination, "@", 2)
   144→		if len(parts) != 2 {
   145→			return "", "", fmt.Errorf("invalid SSH destination format: %s", destination)
   146→		}
   147→		user = parts[0]
   148→		host = parts[1]
   149→	} else {
   150→		// No user specified, use current user
   151→		user = GetSSHUser()
   152→		host = destination
   153→	}
   154→
   155→	// Remove port if present (host:port)
   156→	if strings.Contains(host, ":") {
   157→		parts := strings.SplitN(host, ":", 2)
   158→		host = parts[0]
   159→	}
   160→
   161→	return user, host, nil
   162→}
   163→
   164→// FormatSSHCommand formats an SSH command with the given parameters
   165→func FormatSSHCommand(user, host, command string) string {
   166→	if user == "" {
   167→		return fmt.Sprintf("ssh %s '%s'", host, command)
   168→	}
   169→	return fmt.Sprintf("ssh %s@%s '%s'", user, host, command)
   170→}
   171→
   172→// GetRemoteInfo returns comprehensive information about the remote environment
   173→func GetRemoteInfo() map[string]string {
   174→	info := make(map[string]string)
   175→
   176→	// SSH-related environment variables
   177→	sshVars := []string{
   178→		"SSH_CONNECTION",
   179→		"SSH_CLIENT",
   180→		"SSH_TTY",
   181→		"SSH_AUTH_SOCK",
   182→	}
   183→
   184→	for _, v := range sshVars {
   185→		if value := os.Getenv(v); value != "" {
   186→			info[v] = value
   187→		}
   188→	}
   189→
   190→	// User and host information
   191→	info["USER"] = os.Getenv("USER")
   192→	info["LOGNAME"] = os.Getenv("LOGNAME")
   193→	info["HOME"] = os.Getenv("HOME")
   194→
   195→	hostname, err := os.Hostname()
   196→	if err == nil {
   197→		info["HOSTNAME"] = hostname
   198→	}
   199→
   200→	// Working directory
   201→	cwd, err := os.Getwd()
   202→	if err == nil {
   203→		info["PWD"] = cwd
   204→	}
   205→
   206→	return info
   207→}
   208→
   209→// String returns a string representation of SSHInfo
   210→func (s SSHInfo) String() string {
   211→	return fmt.Sprintf("user=%s host=%s client=%s:%s server=%s:%s",
   212→		s.User, s.Host, s.ClientIP, s.ClientPort, s.ServerIP, s.ServerPort)
   213→}
   214→
   215→// IsValid checks if the SSH info contains minimum required information
   216→func (s *SSHInfo) IsValid() bool {
   217→	return s.User != "" && s.Host != ""
   218→}
