     3→import (
     4→	"errors"
     5→	"fmt"
     6→	"strings"
     7→)
     8→
     9→var (
    10→	// ErrInvalidTemplate is returned when a template is invalid
    11→	ErrInvalidTemplate = errors.New("invalid template")
    12→	// ErrMissingPlaceholder is returned when a required placeholder is missing
    13→	ErrMissingPlaceholder = errors.New("missing required placeholder")
    14→)
    15→
    16→// Template represents a command template with placeholders
    17→type Template struct {
    18→	raw          string
    19→	hasUser      bool
    20→	hasHost      bool
    21→	hasPath      bool
    22→	placeholders []string
    23→}
    24→
    25→// TemplateVars holds the values for template substitution
    26→type TemplateVars struct {
    27→	User string
    28→	Host string
    29→	Path string
    30→}
    31→
    32→// NewTemplate creates a new template from a command string
    33→func NewTemplate(command string) (*Template, error) {
    34→	if command == "" {
    35→		return nil, fmt.Errorf("%w: command cannot be empty", ErrInvalidTemplate)
    36→	}
    37→
    38→	t := &Template{
    39→		raw:          command,
    40→		placeholders: make([]string, 0),
    41→	}
    42→
    43→	// Validate for unknown and unclosed placeholders first
    44→	if err := t.validatePlaceholders(); err != nil {
    45→		return nil, err
    46→	}
    47→
    48→	// Check for placeholders
    49→	t.hasUser = strings.Contains(command, "{user}")
    50→	t.hasHost = strings.Contains(command, "{host}")
    51→	t.hasPath = strings.Contains(command, "{path}")
    52→
    53→	// Path is required
    54→	if !t.hasPath {
    55→		return nil, fmt.Errorf("%w: {path}", ErrMissingPlaceholder)
    56→	}
    57→
    58→	// Collect all placeholders
    59→	if t.hasUser {
    60→		t.placeholders = append(t.placeholders, "{user}")
    61→	}
    62→	if t.hasHost {
    63→		t.placeholders = append(t.placeholders, "{host}")
    64→	}
    65→	if t.hasPath {
    66→		t.placeholders = append(t.placeholders, "{path}")
    67→	}
    68→
    69→	return t, nil
    70→}
    71→
    72→// validatePlaceholders checks for unknown placeholders
    73→func (t *Template) validatePlaceholders() error {
    74→	// Valid placeholders
    75→	valid := map[string]bool{
    76→		"{user}": true,
    77→		"{host}": true,
    78→		"{path}": true,
    79→	}
    80→
    81→	// Check for invalid placeholders
    82→	cmd := t.raw
    83→	start := 0
    84→	for {
    85→		idx := strings.Index(cmd[start:], "{")
    86→		if idx == -1 {
    87→			break
    88→		}
    89→		idx += start
    90→
    91→		// Look for the matching closing brace
    92→		end := strings.Index(cmd[idx+1:], "}")
    93→		if end == -1 {
    94→			return fmt.Errorf("%w: unclosed placeholder at position %d", ErrInvalidTemplate, idx)
    95→		}
    96→		end += idx + 1 + 1 // Adjust for the slice starting at idx+1
    97→
    98→		// Check if there's a nested brace (which would be invalid)
    99→		innerBrace := strings.Index(cmd[idx+1:end], "{")
   100→		if innerBrace != -1 {
   101→			return fmt.Errorf("%w: unclosed placeholder at position %d", ErrInvalidTemplate, idx)
   102→		}
   103→
   104→		placeholder := cmd[idx:end]
   105→		if !valid[placeholder] {
   106→			return fmt.Errorf("%w: unknown placeholder %s", ErrInvalidTemplate, placeholder)
   107→		}
   108→
   109→		start = end
   110→	}
   111→
   112→	return nil
   113→}
   114→
   115→// Render applies the template variables to generate the final command
   116→func (t *Template) Render(vars TemplateVars) (string, error) {
   117→	// Validate required variables
   118→	if t.hasPath && vars.Path == "" {
   119→		return "", fmt.Errorf("path is required for this template")
   120→	}
   121→	if t.hasUser && vars.User == "" {
   122→		return "", fmt.Errorf("user is required for this template")
   123→	}
   124→	if t.hasHost && vars.Host == "" {
   125→		return "", fmt.Errorf("host is required for this template")
   126→	}
   127→
   128→	// Perform substitution
   129→	result := t.raw
   130→	result = strings.ReplaceAll(result, "{user}", vars.User)
   131→	result = strings.ReplaceAll(result, "{host}", vars.Host)
   132→	result = strings.ReplaceAll(result, "{path}", vars.Path)
   133→
   134→	return result, nil
   135→}
   136→
   137→// RenderWithDefaults renders the template with default values for missing vars
   138→func (t *Template) RenderWithDefaults(vars TemplateVars) string {
   139→	result := t.raw
   140→
   141→	// Use provided values or defaults
   142→	user := vars.User
   143→	if user == "" {
   144→		user = "user"
   145→	}
   146→
   147→	host := vars.Host
   148→	if host == "" {
   149→		host = "localhost"
   150→	}
   151→
   152→	path := vars.Path
   153→	if path == "" {
   154→		path = "."
   155→	}
   156→
   157→	result = strings.ReplaceAll(result, "{user}", user)
   158→	result = strings.ReplaceAll(result, "{host}", host)
   159→	result = strings.ReplaceAll(result, "{path}", path)
   160→
   161→	return result
   162→}
   163→
   164→// RequiresUser returns true if the template requires a user variable
   165→func (t *Template) RequiresUser() bool {
   166→	return t.hasUser
   167→}
   168→
   169→// RequiresHost returns true if the template requires a host variable
   170→func (t *Template) RequiresHost() bool {
   171→	return t.hasHost
   172→}
   173→
   174→// RequiresPath returns true if the template requires a path variable
   175→func (t *Template) RequiresPath() bool {
   176→	return t.hasPath
   177→}
   178→
   179→// GetPlaceholders returns the list of placeholders in the template
   180→func (t *Template) GetPlaceholders() []string {
   181→	return t.placeholders
   182→}
   183→
   184→// String returns the raw template string
   185→func (t *Template) String() string {
   186→	return t.raw
   187→}
   188→
   189→// Clone creates a copy of the template
   190→func (t *Template) Clone() *Template {
   191→	return &Template{
   192→		raw:          t.raw,
   193→		hasUser:      t.hasUser,
   194→		hasHost:      t.hasHost,
   195→		hasPath:      t.hasPath,
   196→		placeholders: append([]string(nil), t.placeholders...),
   197→	}
   198→}
   199→
   200→// EscapePath escapes special characters in a path for shell commands
   201→func EscapePath(path string) string {
   202→	// Basic shell escaping - in production, use a proper shell escaping library
   203→	if strings.ContainsAny(path, " \t\n'\"\\$`!") {
   204→		// Use single quotes and escape single quotes
   205→		escaped := strings.ReplaceAll(path, "'", "'\\''")
   206→		return "'" + escaped + "'"
   207→	}
   208→	return path
   209→}
   210→
   211→// ExpandPath expands ~ to home directory and resolves relative paths
   212→func ExpandPath(path string) string {
   213→	if strings.HasPrefix(path, "~/") {
   214→		// In a real implementation, get the actual home directory
   215→		// For now, just return as-is since this is called from remote
   216→		return path
   217→	}
   218→	return path
   219→}
   220→
   221→// ValidateVars validates template variables
   222→func ValidateVars(vars TemplateVars) error {
   223→	if vars.Path == "" {
   224→		return errors.New("path cannot be empty")
   225→	}
   226→
   227→	// Path traversal check
   228→	if strings.Contains(vars.Path, "../") {
   229→		return errors.New("path traversal detected")
   230→	}
   231→
   232→	return nil
   233→}
   234→
   235→// ParseCommand parses a command string into executable and arguments
   236→func ParseCommand(command string) (executable string, args []string) {
   237→	parts := strings.Fields(command)
   238→	if len(parts) == 0 {
   239→		return "", nil
   240→	}
   241→
   242→	executable = parts[0]
   243→	args = parts[1:]
   244→
   245→	return executable, args
   246→}
   247→
   248→// BuildCommand builds a command string from executable and arguments
   249→func BuildCommand(executable string, args []string) string {
   250→	if len(args) == 0 {
   251→		return executable
   252→	}
   253→	return executable + " " + strings.Join(args, " ")
   254→}
