   123→// TailscaleSource provides hosts via Tailscale auto-detection.
   124→type TailscaleSource struct {
   125→	// Enabled indicates whether Tailscale detection is enabled.
   126→	Enabled bool
   127→	// HostPattern is the pattern for generating Tailscale hostname (e.g., "{hostname-}tail").
   128→	HostPattern string
   129→	// ClientIP is the SSH client IP for detecting Tailscale connection.
   130→	ClientIP string
   131→}
   132→
   133→// Name returns the source name.
   134→func (s *TailscaleSource) Name() string { return "tailscale" }
