   138→
   139→// Resolve attempts to detect and return Tailscale host.
   140→func (s *TailscaleSource) Resolve(hostType HostType) string {
   141→	if !s.Enabled {
   142→		return ""
   143→	}
   144→
   145→	// Check if Tailscale is available
   146→	tailscaleIP := getTailscaleInterfaceIP()
   147→	if tailscaleIP == "" {
   148→		return ""
   149→	}
   150→
   151→	// Check if connection is via Tailscale
   152→	isViaTS := isTailscaleIP(s.ClientIP) || (tailscaleIP != "" && os.Getenv("SSH_TTY") != "")
   153→	if !isViaTS {
   154→		return ""
   155→	}
   156→
   157→	switch hostType {
   158→	case ServerHost:
   159→		// Return the Tailscale IP for server connection
   160→		return tailscaleIP
   161→	case SSHHost:
   162→		// Generate Tailscale hostname for SSH
   163→		hostname := getTailscaleHostname()
   164→		if hostname == "" {
   165→			return ""
   166→		}
   167→		return applyTailscalePattern(hostname, s.HostPattern)
   168→	}
   169→	return ""
   170→}
