   212→// Helper functions for Tailscale detection
   213→
   214→// isTailscaleIP checks if an IP is in the Tailscale range (100.64.0.0/10).
   215→func isTailscaleIP(ipStr string) bool {
   216→	if ipStr == "" {
   217→		return false
   218→	}
   219→	ip := net.ParseIP(ipStr)
   220→	if ip == nil {
   221→		return false
   222→	}
   223→	_, tailscaleNet, _ := net.ParseCIDR("100.64.0.0/10")
   224→	return tailscaleNet != nil && tailscaleNet.Contains(ip)
   225→}
   226→
   227→// getTailscaleInterfaceIP returns the Tailscale interface IP if available.
   228→func getTailscaleInterfaceIP() string {
   229→	ifaces, err := net.Interfaces()
   230→	if err != nil {
   231→		return ""
   232→	}
   233→
   234→	for _, iface := range ifaces {
   235→		if iface.Name == "tailscale0" || strings.HasPrefix(iface.Name, "utun") {
   236→			addrs, err := iface.Addrs()
   237→			if err != nil {
   238→				continue
   239→			}
   240→			for _, addr := range addrs {
   241→				if ipnet, ok := addr.(*net.IPNet); ok && ipnet.IP.To4() != nil {
   242→					if isTailscaleIP(ipnet.IP.String()) {
   243→						return ipnet.IP.String()
   244→					}
   245→				}
   246→			}
   247→		}
   248→	}
   249→	return ""
   250→}
   251→
   252→// tailscaleStatus represents the minimal Tailscale status structure.
   253→type tailscaleStatus struct {
   254→	Self struct {
   255→		HostName string `json:"HostName"`
   256→		DNSName  string `json:"DNSName"`
   257→	} `json:"Self"`
   258→}
   259→
   260→// getTailscaleHostname retrieves the hostname from Tailscale.
   261→func getTailscaleHostname() string {
   262→	cmd := exec.Command("tailscale", "status", "--json")
   263→	output, err := cmd.Output()
   264→	if err != nil {
   265→		return ""
   266→	}
   267→
   268→	var status tailscaleStatus
   269→	if err := json.Unmarshal(output, &status); err != nil {
   270→		return ""
   271→	}
   272→
   273→	if status.Self.HostName != "" {
   274→		return status.Self.HostName
   275→	}
   276→	if status.Self.DNSName != "" {
   277→		return status.Self.DNSName
   278→	}
   279→	return ""
   280→}
   281→
   282→// applyTailscalePattern applies the hostname pattern for Tailscale.
   283→func applyTailscalePattern(hostname, pattern string) string {
   284→	// Strip common Tailscale suffixes
   285→	baseName := strings.TrimSuffix(hostname, ".tail75a81.ts.net.")
   286→	baseName = strings.TrimSuffix(baseName, ".ts.net.")
   287→
   288→	if pattern == "" {
   289→		// Default pattern: ws-01 -> ws01tail
   290→		return strings.ReplaceAll(baseName, "-", "") + "tail"
   291→	}
   292→
   293→	// Apply pattern
   294→	result := strings.ReplaceAll(pattern, "{hostname}", baseName)
   295→	result = strings.ReplaceAll(result, "{hostname-}", strings.ReplaceAll(baseName, "-", ""))
   296→	return result
   297→}
   298→
   299→// ExtractSSHClientIP extracts the client IP from SSH environment variables.
   300→func ExtractSSHClientIP() string {
   301→	// Check SSH_CONNECTION first: client_ip client_port server_ip server_port
   302→	if conn := os.Getenv("SSH_CONNECTION"); conn != "" {
   303→		parts := strings.Fields(conn)
   304→		if len(parts) >= 1 {
   305→			return parts[0]
   306→		}
   307→	}
   308→	// Check SSH_CLIENT: client_ip client_port server_port
   309→	if client := os.Getenv("SSH_CLIENT"); client != "" {
   310→		parts := strings.Fields(client)
   311→		if len(parts) >= 1 {
   312→			return parts[0]
   313→		}
   314→	}
   315→	return ""
   316→}
