   101→
   102→	// First, parse legacy fields from the raw data
   103→	var legacy legacyClientConfig
   104→	_ = yaml.Unmarshal(data, &legacy) // Ignore errors, just capture what we can
   105→
   106→	// Parse into new config structure
   107→	var config ClientConfig
   108→	if err := yaml.Unmarshal(data, &config); err != nil {
   109→		return nil, fmt.Errorf("failed to parse config file: %w", err)
   110→	}
   111→
