   113→	legacyWarnings := MigrateFromLegacy(&legacy, &config)
   114→
   115→	// Run additional migrations
   116→	warnings := MigrateClientConfig(&config)
   117→
   118→	// Apply defaults for missing values
   119→	applyClientDefaults(&config)
   120→
   121→	// If legacy fields were migrated, auto-save the new format
   122→	if len(legacyWarnings) > 0 {
   123→		if err := autoMigrateConfigFile(configPath, &config, legacyWarnings); err != nil {
   124→			// Print warnings if auto-migration failed
   125→			fmt.Fprintf(os.Stderr, "Warning: Failed to auto-migrate config file: %v\n", err)
   126→			PrintMigrationWarnings(legacyWarnings)
   127→		}
   128→	}
   129→
   130→	// Print any additional migration warnings
   131→	PrintMigrationWarnings(warnings)
   132→
   133→	return &config, nil
   134→}
