   136→// autoMigrateConfigFile backs up the old config and saves the new format
   137→func autoMigrateConfigFile(configPath string, config *ClientConfig, warnings []MigrationWarning) error {
   138→	// Create backup path
   139→	backupPath := configPath + ".bak"
   140→
   141→	// Check if backup already exists (don't overwrite previous backups)
   142→	if _, err := os.Stat(backupPath); err == nil {
   143→		// Backup exists, use numbered backup
   144→		for i := 1; i < 100; i++ {
   145→			backupPath = fmt.Sprintf("%s.bak.%d", configPath, i)
   146→			if _, err := os.Stat(backupPath); os.IsNotExist(err) {
   147→				break
   148→			}
   149→		}
   150→	}
   151→
   152→	// Read original file for backup
   153→	// configPath is from user configuration or default path, not external input
   154→	originalData, err := os.ReadFile(configPath) // #nosec G304
   155→	if err != nil {
   156→		return fmt.Errorf("failed to read original config: %w", err)
   157→	}
   158→
   159→	// Write backup
   160→	if err := os.WriteFile(backupPath, originalData, 0o600); err != nil {
   161→		return fmt.Errorf("failed to create backup: %w", err)
   162→	}
   163→
   164→	// Save new format
   165→	if err := SaveClientConfig(configPath, config); err != nil {
   166→		return fmt.Errorf("failed to save migrated config: %w", err)
   167→	}
   168→
   169→	// Print migration success message
   170→	fmt.Fprintf(os.Stderr, "Config file migrated to new format.\n")
   171→	fmt.Fprintf(os.Stderr, "  Backup saved to: %s\n", backupPath)
   172→	fmt.Fprintf(os.Stderr, "  Migrated fields:\n")
   173→	for _, w := range warnings {
   174→		fmt.Fprintf(os.Stderr, "    - %s: %s\n", w.Field, w.Message)
   175→	}
   176→
   177→	return nil
   178→}
