package main

import (
	"strings"
	"testing"

	"github.com/foxytanuki/rcode/internal/config"
	"github.com/foxytanuki/rcode/internal/logger"
)

func TestBuildCommand(t *testing.T) {
	executor := createTestExecutor()

	tests := []struct {
		name     string
		template string
		user     string
		host     string
		path     string
		want     string
	}{
		{
			name:     "all placeholders",
			template: "ssh {user}@{host} 'editor {path}'",
			user:     "testuser",
			host:     "testhost",
			path:     "/home/project",
			want:     "ssh testuser@testhost 'editor /home/project'",
		},
		{
			name:     "path only",
			template: "editor {path}",
			user:     "testuser",
			host:     "testhost",
			path:     "/home/project",
			want:     "editor /home/project",
		},
		{
			name:     "multiple occurrences",
			template: "{user}@{host}:{path} -> {user}",
			user:     "alice",
			host:     "server",
			path:     "/tmp",
			want:     "alice@server:/tmp -> alice",
		},
		{
			name:     "no placeholders",
			template: "static command",
			user:     "testuser",
			host:     "testhost",
			path:     "/home/project",
			want:     "static command",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := executor.buildCommand(tt.template, tt.user, tt.host, tt.path)
			if got != tt.want {
				t.Errorf("buildCommand() = %v, want %v", got, tt.want)
			}
		})
	}
}

func TestGetDefaultEditor(t *testing.T) {
	tests := []struct {
		name    string
		editors []config.EditorConfig
		want    string
	}{
		{
			name: "explicitly marked default",
			editors: []config.EditorConfig{
				{Name: "editor1", Command: "cmd1 {path}", Default: false},
				{Name: "editor2", Command: "cmd2 {path}", Default: true},
				{Name: "editor3", Command: "cmd3 {path}", Default: false},
			},
			want: "editor2",
		},
		{
			name: "first available when no default",
			editors: []config.EditorConfig{
				{Name: "editor1", Command: "unavailable {path}", Available: false},
				{Name: "editor2", Command: "echo {path}", Available: true},
				{Name: "editor3", Command: "cmd3 {path}", Available: false},
			},
			want: "editor2",
		},
		{
			name: "first editor when none available",
			editors: []config.EditorConfig{
				{Name: "editor1", Command: "cmd1 {path}", Available: false},
				{Name: "editor2", Command: "cmd2 {path}", Available: false},
			},
			want: "editor1",
		},
		{
			name:    "no editors",
			editors: []config.EditorConfig{},
			want:    "",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			executor := &Executor{
				editors:      tt.editors,
				log:          createTestLogger(),
				availability: make(map[string]bool),
			}

			// Set availability based on Available field
			for _, editor := range tt.editors {
				executor.availability[editor.Name] = editor.Available
			}

			editor := executor.getDefaultEditor()
			if tt.want == "" {
				if editor != nil {
					t.Errorf("getDefaultEditor() = %v, want nil", editor.Name)
				}
			} else {
				if editor == nil {
					t.Errorf("getDefaultEditor() = nil, want %v", tt.want)
				} else if editor.Name != tt.want {
					t.Errorf("getDefaultEditor() = %v, want %v", editor.Name, tt.want)
				}
			}
		})
	}
}

func TestValidateEditorConfig(t *testing.T) {
	executor := createTestExecutor()

	tests := []struct {
		name    string
		editor  config.EditorConfig
		wantErr bool
		errMsg  string
	}{
		{
			name: "valid config",
			editor: config.EditorConfig{
				Name:    "test",
				Command: "editor {path}",
			},
			wantErr: false,
		},
		{
			name: "missing name",
			editor: config.EditorConfig{
				Name:    "",
				Command: "editor {path}",
			},
			wantErr: true,
			errMsg:  "name cannot be empty",
		},
		{
			name: "missing command",
			editor: config.EditorConfig{
				Name:    "test",
				Command: "",
			},
			wantErr: true,
			errMsg:  "command cannot be empty",
		},
		{
			name: "missing path placeholder",
			editor: config.EditorConfig{
				Name:    "test",
				Command: "editor file.txt",
			},
			wantErr: true,
			errMsg:  "must contain {path}",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := executor.ValidateEditorConfig(tt.editor)
			if tt.wantErr {
				if err == nil {
					t.Error("ValidateEditorConfig() error = nil, want error")
				} else if !strings.Contains(err.Error(), tt.errMsg) {
					t.Errorf("ValidateEditorConfig() error = %v, want containing %v", err, tt.errMsg)
				}
			} else {
				if err != nil {
					t.Errorf("ValidateEditorConfig() error = %v, want nil", err)
				}
			}
		})
	}
}

func TestIsEditorAvailable(t *testing.T) {
	executor := createTestExecutor()

	// Mock availability
	executor.availability["available"] = true
	executor.availability["unavailable"] = false

	tests := []struct {
		name   string
		editor string
		want   bool
	}{
		{"available editor", "available", true},
		{"unavailable editor", "unavailable", false},
		{"unknown editor", "unknown", false},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := executor.IsEditorAvailable(tt.editor)
			if got != tt.want {
				t.Errorf("IsEditorAvailable(%v) = %v, want %v", tt.editor, got, tt.want)
			}
		})
	}
}

func TestOpenEditor(t *testing.T) {
	executor := createTestExecutor()

	// Add a test editor that uses echo command (should be available on most systems)
	executor.editors = []config.EditorConfig{
		{
			Name:      "echo-editor",
			Command:   "echo Opening {path} for {user}@{host}",
			Default:   true,
			Available: true,
		},
		{
			Name:      "unknown-editor",
			Command:   "nonexistent-command {path}",
			Default:   false,
			Available: false,
		},
	}
	executor.availability["echo-editor"] = true
	executor.availability["unknown-editor"] = false

	tests := []struct {
		name       string
		editorName string
		user       string
		host       string
		path       string
		wantErr    bool
	}{
		{
			name:       "valid editor",
			editorName: "echo-editor",
			user:       "testuser",
			host:       "testhost",
			path:       "/test/path",
			wantErr:    false,
		},
		{
			name:       "default editor (empty name)",
			editorName: "",
			user:       "testuser",
			host:       "testhost",
			path:       "/test/path",
			wantErr:    false,
		},
		{
			name:       "non-existent editor",
			editorName: "nonexistent",
			user:       "testuser",
			host:       "testhost",
			path:       "/test/path",
			wantErr:    true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			command, err := executor.OpenEditor(tt.editorName, tt.user, tt.host, tt.path)

			if tt.wantErr {
				if err == nil {
					t.Error("OpenEditor() error = nil, want error")
				}
			} else {
				if err != nil {
					t.Errorf("OpenEditor() error = %v, want nil", err)
				}
				if command == "" {
					t.Error("OpenEditor() returned empty command")
				}
			}
		})
	}
}

// Helper functions for testing
func createTestExecutor() *Executor {
	editors := []config.EditorConfig{
		{
			Name:      "test-editor",
			Command:   "test-cmd {path}",
			Default:   true,
			Available: true,
		},
	}

	return NewExecutor(editors, createTestLogger())
}

func createTestLogger() *logger.Logger {
	return logger.New(&logger.Config{
		Level:   "error", // Quiet for tests
		Console: false,
	})
}

package editor

import (
	"errors"
	"fmt"
	"os/exec"
	"strings"
	"sync"

	"github.com/foxytanuki/rcode/internal/config"
	"github.com/foxytanuki/rcode/internal/logger"
)

var (
	// ErrNoEditors is returned when no editors are configured
	ErrNoEditors = errors.New("no editors configured")
	// ErrEditorNotFound is returned when a requested editor is not found
	ErrEditorNotFound = errors.New("editor not found")
	// ErrNoDefaultEditor is returned when no default editor can be determined
	ErrNoDefaultEditor = errors.New("no default editor available")
	// ErrInvalidEditor is returned when editor configuration is invalid
	ErrInvalidEditor = errors.New("invalid editor configuration")
)

// Manager manages available editors
type Manager struct {
	editors      map[string]*Editor
	defaultName  string
	log          *logger.Logger
	mu           sync.RWMutex
	availability map[string]bool
	availMu      sync.RWMutex
}

// Editor represents a single editor configuration
type Editor struct {
	Name      string
	Command   string
	Default   bool
	Available bool
	Template  *Template
}

// NewManager creates a new editor manager
func NewManager(configs []config.EditorConfig, log *logger.Logger) (*Manager, error) {
	if len(configs) == 0 {
		return nil, ErrNoEditors
	}

	m := &Manager{
		editors:      make(map[string]*Editor),
		log:          log,
		availability: make(map[string]bool),
	}

	// Initialize editors from config
	for _, cfg := range configs {
		editor, err := NewEditor(cfg)
		if err != nil {
			log.Warn("Skipping invalid editor configuration",
				"name", cfg.Name,
				"error", err,
			)
			continue
		}

		m.editors[editor.Name] = editor

		// Track default editor
		if editor.Default && m.defaultName == "" {
			m.defaultName = editor.Name
		}
	}

	// If no default was explicitly set, use the first configured editor
	if m.defaultName == "" && len(configs) > 0 {
		// Use the first valid editor from the original config slice
		for _, cfg := range configs {
			if _, exists := m.editors[cfg.Name]; exists {
				m.defaultName = cfg.Name
				break
			}
		}
	}

	// Check availability of all editors
	m.RefreshAvailability()

	return m, nil
}

// NewEditor creates a new editor from configuration
func NewEditor(cfg config.EditorConfig) (*Editor, error) {
	if cfg.Name == "" {
		return nil, fmt.Errorf("%w: name is required", ErrInvalidEditor)
	}

	if cfg.Command == "" {
		return nil, fmt.Errorf("%w: command is required", ErrInvalidEditor)
	}

	template, err := NewTemplate(cfg.Command)
	if err != nil {
		return nil, fmt.Errorf("%w: invalid command template: %v", ErrInvalidEditor, err)
	}

	return &Editor{
		Name:      cfg.Name,
		Command:   cfg.Command,
		Default:   cfg.Default,
		Available: cfg.Available,
		Template:  template,
	}, nil
}

// GetEditor returns an editor by name
func (m *Manager) GetEditor(name string) (*Editor, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	if name == "" {
		return m.getDefaultEditor()
	}

	editor, exists := m.editors[name]
	if !exists {
		return nil, fmt.Errorf("%w: %s", ErrEditorNotFound, name)
	}

	return editor, nil
}

// GetDefaultEditor returns the default editor
func (m *Manager) GetDefaultEditor() (*Editor, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	return m.getDefaultEditor()
}

// getDefaultEditor returns the default editor (must be called with lock held)
func (m *Manager) getDefaultEditor() (*Editor, error) {
	// First try the explicitly set default
	if m.defaultName != "" {
		if editor, exists := m.editors[m.defaultName]; exists {
			return editor, nil
		}
	}

	// Then try to find any available editor
	for name, editor := range m.editors {
		if m.IsAvailable(name) {
			return editor, nil
		}
	}

	// Finally, return any editor
	for _, editor := range m.editors {
		return editor, nil
	}

	return nil, ErrNoDefaultEditor
}

// ListEditors returns all configured editors
func (m *Manager) ListEditors() []*Editor {
	m.mu.RLock()
	defer m.mu.RUnlock()

	editors := make([]*Editor, 0, len(m.editors))
	for _, editor := range m.editors {
		// Create a copy to avoid mutation
		editorCopy := *editor
		editorCopy.Available = m.IsAvailable(editor.Name)
		editors = append(editors, &editorCopy)
	}

	return editors
}

// IsAvailable checks if an editor is available on the system
func (m *Manager) IsAvailable(name string) bool {
	m.availMu.RLock()
	available, exists := m.availability[name]
	m.availMu.RUnlock()

	if exists {
		return available
	}

	// Check availability if not cached
	m.mu.RLock()
	editor, editorExists := m.editors[name]
	m.mu.RUnlock()

	if !editorExists {
		return false
	}

	available = m.checkAvailability(editor)

	m.availMu.Lock()
	m.availability[name] = available
	m.availMu.Unlock()

	return available
}

// RefreshAvailability refreshes the availability status of all editors
func (m *Manager) RefreshAvailability() {
	m.mu.RLock()
	editors := make([]*Editor, 0, len(m.editors))
	for _, editor := range m.editors {
		editors = append(editors, editor)
	}
	m.mu.RUnlock()

	m.availMu.Lock()
	defer m.availMu.Unlock()

	for _, editor := range editors {
		available := m.checkAvailability(editor)
		m.availability[editor.Name] = available

		if available {
			m.log.Debug("Editor available",
				"name", editor.Name,
				"default", editor.Default,
			)
		} else {
			m.log.Debug("Editor not available",
				"name", editor.Name,
			)
		}
	}
}

// checkAvailability checks if an editor is available
func (m *Manager) checkAvailability(editor *Editor) bool {
	// Extract the executable from the command
	executable := m.extractExecutable(editor.Command)
	if executable == "" {
		return false
	}

	// Check if the executable exists in PATH
	_, err := exec.LookPath(executable)
	return err == nil
}

// extractExecutable extracts the executable name from a command string
func (m *Manager) extractExecutable(command string) string {
	// Find the first part before any flags or arguments
	parts := strings.Fields(command)
	if len(parts) == 0 {
		return ""
	}

	// The executable is the first part
	executable := parts[0]

	// Remove any template variables from the executable name
	if strings.Contains(executable, "{") {
		return ""
	}

	return executable
}

// SetDefault sets the default editor
func (m *Manager) SetDefault(name string) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	if _, exists := m.editors[name]; !exists {
		return fmt.Errorf("%w: %s", ErrEditorNotFound, name)
	}

	// Clear previous default
	for _, editor := range m.editors {
		editor.Default = false
	}

	// Set new default
	m.editors[name].Default = true
	m.defaultName = name

	m.log.Info("Default editor changed", "editor", name)

	return nil
}

// AddEditor adds a new editor to the manager
func (m *Manager) AddEditor(cfg config.EditorConfig) error {
	editor, err := NewEditor(cfg)
	if err != nil {
		return err
	}

	m.mu.Lock()
	defer m.mu.Unlock()

	m.editors[editor.Name] = editor

	// Check availability
	available := m.checkAvailability(editor)
	m.availMu.Lock()
	m.availability[editor.Name] = available
	m.availMu.Unlock()

	m.log.Info("Editor added",
		"name", editor.Name,
		"available", available,
	)

	return nil
}

// RemoveEditor removes an editor from the manager
func (m *Manager) RemoveEditor(name string) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	if _, exists := m.editors[name]; !exists {
		return fmt.Errorf("%w: %s", ErrEditorNotFound, name)
	}

	delete(m.editors, name)

	m.availMu.Lock()
	delete(m.availability, name)
	m.availMu.Unlock()

	// Update default if necessary
	if m.defaultName == name {
		m.defaultName = ""
		for editorName := range m.editors {
			m.defaultName = editorName
			break
		}
	}

	m.log.Info("Editor removed", "name", name)

	return nil
}

// ValidateEditor validates an editor configuration
func ValidateEditor(cfg config.EditorConfig) error {
	if cfg.Name == "" {
		return fmt.Errorf("%w: name is required", ErrInvalidEditor)
	}

	if cfg.Command == "" {
		return fmt.Errorf("%w: command is required", ErrInvalidEditor)
	}

	// Validate command template
	if _, err := NewTemplate(cfg.Command); err != nil {
		return fmt.Errorf("%w: invalid command template: %v", ErrInvalidEditor, err)
	}

	return nil
}

// Count returns the number of configured editors
func (m *Manager) Count() int {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return len(m.editors)
}

// GetDefaultName returns the name of the default editor
func (m *Manager) GetDefaultName() string {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return m.defaultName
}

// Package editor handles editor command execution.
package editor

import (
	"context"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"strings"
	"time"

	"github.com/foxytanuki/rcode/internal/logger"
)

var (
	// ErrExecutionFailed is returned when command execution fails
	ErrExecutionFailed = errors.New("command execution failed")
	// ErrTimeout is returned when command execution times out
	ErrTimeout = errors.New("command execution timeout")
)

// Executor handles the execution of editor commands
type Executor struct {
	manager *Manager
	log     *logger.Logger
	timeout time.Duration
}

// ExecutorOption is a functional option for configuring the executor
type ExecutorOption func(*Executor)

// WithTimeout sets the execution timeout
func WithTimeout(timeout time.Duration) ExecutorOption {
	return func(e *Executor) {
		e.timeout = timeout
	}
}

// NewExecutor creates a new executor
func NewExecutor(manager *Manager, log *logger.Logger, opts ...ExecutorOption) *Executor {
	e := &Executor{
		manager: manager,
		log:     log,
		timeout: 30 * time.Second, // Default timeout
	}

	for _, opt := range opts {
		opt(e)
	}

	return e
}

// Execute opens a file/directory in the specified editor
func (e *Executor) Execute(editorName string, vars TemplateVars) error {
	// Validate variables
	if err := ValidateVars(vars); err != nil {
		return fmt.Errorf("invalid variables: %w", err)
	}

	// Get the editor
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return err
	}

	// Check availability
	if !e.manager.IsAvailable(editor.Name) {
		e.log.Warn("Editor not available, attempting anyway",
			"editor", editor.Name,
		)
	}

	// Render the command template
	command, err := editor.Template.Render(vars)
	if err != nil {
		return fmt.Errorf("failed to render template: %w", err)
	}

	// Log the execution
	e.log.Info("Executing editor command",
		"editor", editor.Name,
		"command", command,
		"user", vars.User,
		"host", vars.Host,
		"path", vars.Path,
	)

	// Execute the command
	if err := e.executeCommand(command); err != nil {
		return fmt.Errorf("%w: %v", ErrExecutionFailed, err)
	}

	e.log.Info("Editor launched successfully",
		"editor", editor.Name,
		"path", vars.Path,
	)

	return nil
}

// ExecuteDefault opens a file/directory in the default editor
func (e *Executor) ExecuteDefault(vars TemplateVars) error {
	editor, err := e.manager.GetDefaultEditor()
	if err != nil {
		return err
	}

	return e.Execute(editor.Name, vars)
}

// executeCommand executes the editor command
func (e *Executor) executeCommand(command string) error {
	// Parse command
	executable, args := ParseCommand(command)
	if executable == "" {
		return errors.New("empty command")
	}

	// Create command - args are passed separately to prevent shell injection
	cmd := exec.Command(executable, args...) // #nosec G204

	// For GUI editors, we want to detach from the parent process
	cmd.Stdout = nil
	cmd.Stderr = nil
	cmd.Stdin = nil

	// Set environment variables if needed
	cmd.Env = os.Environ()

	// Start the command
	if err := cmd.Start(); err != nil {
		return fmt.Errorf("failed to start editor: %w", err)
	}

	// For GUI applications, release the process so we don't wait
	if err := cmd.Process.Release(); err != nil {
		// Non-critical error, just log it
		e.log.Debug("Failed to release process", "error", err)
	}

	return nil
}

// ExecuteWithContext executes a command with a context for cancellation
func (e *Executor) ExecuteWithContext(ctx context.Context, editorName string, vars TemplateVars) error {
	// Create a channel to signal completion
	done := make(chan error, 1)

	// Execute in a goroutine
	go func() {
		done <- e.Execute(editorName, vars)
	}()

	// Wait for completion or context cancellation
	select {
	case err := <-done:
		return err
	case <-ctx.Done():
		return fmt.Errorf("%w: %v", ErrTimeout, ctx.Err())
	}
}

// ExecuteAndWait executes a command and waits for it to complete
func (e *Executor) ExecuteAndWait(editorName string, vars TemplateVars) error {
	// Get the editor
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return err
	}

	// Render the command template
	command, err := editor.Template.Render(vars)
	if err != nil {
		return fmt.Errorf("failed to render template: %w", err)
	}

	// Parse command
	executable, args := ParseCommand(command)
	if executable == "" {
		return errors.New("empty command")
	}

	// Create command with context for timeout
	ctx, cancel := context.WithTimeout(context.Background(), e.timeout)
	defer cancel()

	// Args are passed separately to prevent shell injection
	cmd := exec.CommandContext(ctx, executable, args...) // #nosec G204

	// Log the execution
	e.log.Debug("Executing and waiting for editor",
		"editor", editor.Name,
		"command", command,
		"timeout", e.timeout,
	)

	// Run the command and wait for completion
	output, err := cmd.CombinedOutput()
	if err != nil {
		if ctx.Err() == context.DeadlineExceeded {
			return fmt.Errorf("%w after %v", ErrTimeout, e.timeout)
		}
		return fmt.Errorf("%w: %v (output: %s)", ErrExecutionFailed, err, string(output))
	}

	return nil
}

// TestCommand tests if a command can be executed without actually running it
func (e *Executor) TestCommand(editorName string, vars TemplateVars) error {
	// Get the editor
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return err
	}

	// Validate variables
	if err := ValidateVars(vars); err != nil {
		return fmt.Errorf("invalid variables: %w", err)
	}

	// Render the command template
	command, err := editor.Template.Render(vars)
	if err != nil {
		return fmt.Errorf("failed to render template: %w", err)
	}

	// Parse command
	executable, _ := ParseCommand(command)
	if executable == "" {
		return errors.New("empty command")
	}

	// Check if executable exists
	if _, err := exec.LookPath(executable); err != nil {
		return fmt.Errorf("executable not found: %w", err)
	}

	return nil
}

// ListAvailableEditors returns a list of available editors
func (e *Executor) ListAvailableEditors() []string {
	editors := e.manager.ListEditors()
	available := make([]string, 0, len(editors))

	for _, editor := range editors {
		if e.manager.IsAvailable(editor.Name) {
			available = append(available, editor.Name)
		}
	}

	return available
}

// GetEditorCommand returns the rendered command for an editor
func (e *Executor) GetEditorCommand(editorName string, vars TemplateVars) (string, error) {
	// Get the editor
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return "", err
	}

	// Render the command template
	command, err := editor.Template.Render(vars)
	if err != nil {
		return "", fmt.Errorf("failed to render template: %w", err)
	}

	return command, nil
}

// ExecuteCustom executes a custom command with the given template
func (e *Executor) ExecuteCustom(commandTemplate string, vars TemplateVars) error {
	// Create a temporary template
	template, err := NewTemplate(commandTemplate)
	if err != nil {
		return fmt.Errorf("invalid template: %w", err)
	}

	// Render the command
	command, err := template.Render(vars)
	if err != nil {
		return fmt.Errorf("failed to render template: %w", err)
	}

	// Log the execution
	e.log.Debug("Executing custom command",
		"command", command,
		"user", vars.User,
		"host", vars.Host,
		"path", vars.Path,
	)

	// Execute the command
	if err := e.executeCommand(command); err != nil {
		return fmt.Errorf("%w: %v", ErrExecutionFailed, err)
	}

	return nil
}

// RefreshAvailability refreshes the availability status of all editors
func (e *Executor) RefreshAvailability() {
	e.manager.RefreshAvailability()
}

// SupportsRemoteEditing checks if an editor supports remote editing
func (e *Executor) SupportsRemoteEditing(editorName string) bool {
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return false
	}

	// Check if the command template includes host/user variables
	return editor.Template.RequiresHost() || editor.Template.RequiresUser()
}

// NormalizeEditorName normalizes an editor name for case-insensitive lookup
func NormalizeEditorName(name string) string {
	return strings.ToLower(strings.TrimSpace(name))
}

