package main

import (
	"net/http"
	"time"

	"github.com/foxytanuki/rcode/internal/config"
	"github.com/foxytanuki/rcode/internal/logger"
)

// Server represents the HTTP server
type Server struct {
	config    *config.ServerConfigFile
	log       *logger.Logger
	executor  *Executor
	startTime time.Time
}

// NewServer creates a new server instance
func NewServer(cfg *config.ServerConfigFile, log *logger.Logger) *Server {
	return &Server{
		config:    cfg,
		log:       log,
		executor:  NewExecutor(cfg.Editors, log),
		startTime: time.Now(),
	}
}

// Router returns the HTTP handler with all routes configured
func (s *Server) Router() http.Handler {
	mux := http.NewServeMux()

	// Apply middleware
	handler := s.withMiddleware(mux)

	// Register routes
	mux.HandleFunc("/health", s.handleHealth)
	mux.HandleFunc("/editors", s.handleEditors)
	mux.HandleFunc("/open-editor", s.handleOpenEditor)

	return handler
}

// withMiddleware applies middleware to the handler
func (s *Server) withMiddleware(handler http.Handler) http.Handler {
	// Apply middleware in reverse order (last one runs first)
	handler = s.recoveryMiddleware(handler)
	handler = s.loggingMiddleware(handler)
	handler = s.ipWhitelistMiddleware(handler)
	return handler
}

package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	"github.com/foxytanuki/rcode/internal/version"
	"github.com/foxytanuki/rcode/pkg/api"
)

// handleHealth handles GET /health
func (s *Server) handleHealth(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		s.respondError(w, api.ErrNotImplemented, http.StatusMethodNotAllowed, "Method not allowed")
		return
	}

	uptime := time.Since(s.startTime).Seconds()
	response := api.HealthResponse{
		Status:    "healthy",
		Version:   version.Version,
		Uptime:    int64(uptime),
		StartedAt: s.startTime,
	}
	response.SetTimestamp()

	s.respondJSON(w, http.StatusOK, response)
}

